function setHeroHeight() { const hero = document.querySelector('#hero'); if (hero) { const navbar = document.querySelector('.navbar'); const navbarHeight = navbar ? navbar.offsetHeight : 0; const remainingHeight = window.innerHeight; hero.style.minHeight = `${remainingHeight}px`; hero.style.height = `${remainingHeight}px`; hero.style.paddingTop = `${navbarHeight}px`; } } document.addEventListener('DOMContentLoaded', setHeroHeight); window.addEventListener('resize', setHeroHeight); document.querySelectorAll('a[href^="#"]').forEach(anchor => { anchor.addEventListener('click', function (e) { e.preventDefault(); const target = document.querySelector(this.getAttribute('href')); if (target) { target.scrollIntoView({ behavior: 'smooth', block: 'start' }); const navbarCollapse = document.querySelector('.navbar-collapse'); if (navbarCollapse && navbarCollapse.classList.contains('show')) { const bsCollapse = bootstrap.Collapse.getInstance(navbarCollapse); if (bsCollapse) { bsCollapse.hide(); } } } }); }); window.addEventListener('scroll', function() { const navbar = document.querySelector('.navbar'); if (window.scrollY > 50) { navbar.classList.add('scrolled'); } else { navbar.classList.remove('scrolled'); } }); document.addEventListener('DOMContentLoaded', function() { const dropdownToggles = document.querySelectorAll('.dropdown-toggle'); dropdownToggles.forEach(toggle => { toggle.addEventListener('click', function(e) { if (window.innerWidth <= 991) { e.preventDefault(); const dropdown = this.closest('.dropdown'); const menu = dropdown.querySelector('.dropdown-menu'); document.querySelectorAll('.dropdown-menu.show').forEach(m => { if (m !== menu) m.classList.remove('show'); }); menu.classList.toggle('show'); } }); }); document.querySelectorAll('.dropdown-item').forEach(item => { item.addEventListener('click', function() { if (window.innerWidth <= 991) { document.querySelectorAll('.dropdown-menu.show').forEach(m => { m.classList.remove('show'); }); } }); }); }); const contactForm = document.getElementById('contactForm'); if (contactForm) { contactForm.addEventListener('submit', function(e) { e.preventDefault(); const submitBtn = document.getElementById('submitBtn'); const alertDiv = document.getElementById('contactAlert'); submitBtn.disabled = true; submitBtn.textContent = 'Sending...'; alertDiv.style.display = 'none'; const formData = new FormData(); formData.append('action', 'contact'); formData.append('name', this.name.value); formData.append('email', this.email.value); formData.append('phone', this.phone.value); formData.append('subject', this.subject.value); formData.append('message', this.message.value); fetch('enroll.php', { method: 'POST', body: formData }) .then(response => response.json()) .then(data => { alertDiv.textContent = data.message; alertDiv.className = 'alert-custom ' + (data.success ? 'alert-success' : 'alert-error'); alertDiv.style.display = 'block'; alertDiv.scrollIntoView({ behavior: 'smooth', block: 'center' }); if (data.success) { contactForm.reset(); } setTimeout(() => { alertDiv.style.display = 'none'; }, 10000); }) .catch(error => { alertDiv.textContent = 'Connection error. Please try again.'; alertDiv.className = 'alert-custom alert-error'; alertDiv.style.display = 'block'; }) .finally(() => { submitBtn.disabled = false; submitBtn.textContent = 'Send Message'; }); }); } window.addEventListener('scroll', () => { let current = ''; document.querySelectorAll('section').forEach(section => { const sectionTop = section.offsetTop; if (scrollY >= sectionTop - 100) { current = section.getAttribute('id'); } }); document.querySelectorAll('.nav-link').forEach(link => { link.classList.remove('active'); if (link.getAttribute('href') === '#' + current) { link.classList.add('active'); } }); });